const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Load current token
const creds = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/template_credentials?template_id=eq.instagram-post&cred_key=eq.instagram_token&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { status: 'skip', reason: 'No Instagram token configured.' } }];
}

const token = creds[0].cred_value;

// Check token validity and expiry
try {
  const debug = await helpers.httpRequest({
    method: 'GET',
    url: 'https://graph.facebook.com/debug_token?input_token=' + token + '&access_token=' + token
  });

  const data = debug.data;
  if (!data || !data.is_valid) {
    return [{ json: { status: 'expired', reason: 'Token ist ungültig. Neues Token erforderlich.' } }];
  }

  const expiresAt = data.expires_at ? new Date(data.expires_at * 1000) : null;
  const now = new Date();
  const daysLeft = expiresAt ? Math.floor((expiresAt - now) / (1000 * 60 * 60 * 24)) : null;

  if (daysLeft !== null && daysLeft > 7) {
    return [{ json: { status: 'ok', days_left: daysLeft, expires_at: expiresAt.toISOString() } }];
  }

  // Token expires within 7 days — refresh it
  const refreshed = await helpers.httpRequest({
    method: 'GET',
    url: 'https://graph.facebook.com/v21.0/oauth/access_token'
      + '?grant_type=fb_exchange_token'
      + '&client_id=' + token // Long-lived tokens can self-refresh
      + '&fb_exchange_token=' + token
      + '&access_token=' + token
  });

  if (refreshed.access_token) {
    // Save new token
    await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/rest/v1/template_credentials?template_id=eq.instagram-post&cred_key=eq.instagram_token',
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        cred_value: refreshed.access_token,
        updated_at: new Date().toISOString()
      })
    });

    return [{ json: {
      status: 'refreshed',
      old_days_left: daysLeft,
      new_expires_in: refreshed.expires_in ? Math.floor(refreshed.expires_in / 86400) + ' days' : 'unknown'
    } }];
  }

  return [{ json: { status: 'refresh_failed', reason: 'Token-Refresh fehlgeschlagen.', days_left: daysLeft } }];
} catch(e) {
  return [{ json: { status: 'error', reason: e.message } }];
}
